const studentData = $('Supabase → Student Progress').first().json;
const plan = $('Claude → Training Plan').first().json.content?.[0]?.text || 'No plan generated';
const saved = $input.first().json;
const studentId = $('Called by Agent').first().json.student_id || $('Called by Agent').first().json.parameters?.student_id;

return [{ json: {
  status: 'completed',
  workflow: '04_content_training_plan',
  student_id: studentId,
  student_name: studentData?.student?.name || 'Unknown',
  current_belt: studentData?.student?.belt || 'unknown',
  plan_saved: Array.isArray(saved) ? !!saved[0]?.id : !!saved?.id,
  plan_preview: plan.substring(0, 800),
  plan_full: plan,
  completedAt: new Date().toISOString()
} }];
